+#[must_use]
+pub fn cass_has_boolean_operators(query: &str) -> bool {
+    let tokens = cass_parse_boolean_query(query);
+    tokens.iter().any(|t| {
+        matches!(
+            t,
+            CassQueryToken::And
+                | CassQueryToken::Or
+                | CassQueryToken::Not
+                | CassQueryToken::Phrase(_)
+        )
+    })
+}
